from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import os
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = os.environ.get('DATABASE_URL', 'sqlite:///app.db')
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(255), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token = db.Column(db.String(255), unique=True, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)

    user = db.relationship('User', backref=db.backref('password_reset_tokens', lazy=True))

@app.route('/reset-password', methods=['POST'])
def reset_password():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({'message': 'If email exists, reset link sent'}), 200
    
    # Generate secure token
    token = secrets.token_urlsafe(32)
    
    # Create token with 1-hour expiration
    expires_at = datetime.utcnow() + timedelta(hours=1)
    
    # Store token
    reset_token = PasswordResetToken(
        user_id=user.id,
        token=token,
        expires_at=expires_at
    )
    
    db.session.add(reset_token)
    db.session.commit()
    
    # Send reset email (simplified - you'd use a proper email service)
    reset_link = f"https://yourapp.com/reset?token={token}"
    
    try:
        # This is a placeholder - implement your email sending logic
        print(f"Reset link for {email}: {reset_link}")
        # send_email(email, "Password Reset", f"Click here to reset: {reset_link}")
    except Exception as e:
        print(f"Failed to send email: {e}")
    
    return jsonify({'message': 'If email exists, reset link sent'}), 200

@app.route('/reset', methods=['POST'])
def reset_password_confirm():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password required'}), 400
    
    # Find token
    reset_token = PasswordResetToken.query.filter_by(token=token).first()
    
    if not reset_token:
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    # Check if token is expired
    if reset_token.expires_at < datetime.utcnow():
        db.session.delete(reset_token)
        db.session.commit()
        return jsonify({'error': 'Token expired'}), 400
    
    # Update password
    user = User.query.get(reset_token.user_id)
    if user:
        user.password_hash = generate_password_hash(new_password)
        db.session.delete(reset_token)
        db.session.commit()
        return jsonify({'message': 'Password reset successfully'}), 200
    
    return jsonify({'error': 'User not found'}), 404

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
